from flask import Flask, request, jsonify
from prometheus_client import Counter, Histogram, generate_latest, CONTENT_TYPE_LATEST

app = Flask(__name__)

REQUEST_COUNT = Counter('api_request_count', 'Total API Requests', ['method', 'endpoint', 'user_id', 'api_key'])
REQUEST_LATENCY = Histogram('api_request_latency_seconds', 'API Request Latency', ['method', 'endpoint', 'user_id', 'api_key'])

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.before_request
def before_request():
    request.start_time = REQUEST_LATENCY.labels(
        request.method,
        request.path,
        request.headers.get('User-ID', 'unknown'),
        request.headers.get('API-Key', 'unknown')
    ).time()

@app.after_request
def after_request(response):
    request.start_time.observe_duration()
    REQUEST_COUNT.labels(
        request.method,
        request.path,
        request.headers.get('User-ID', 'unknown'),
        request.headers.get('API-Key', 'unknown')
    ).inc()
    return response

@app.route('/example', methods=['GET', 'POST'])
def example():
    data = request.json if request.is_json else {}
    return jsonify({"message": "Example endpoint", "data": data})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)